1	const PROCESSING_FEE = 5;
2	
3	interface Item {
4	  type: string;
5	}
6	
7	interface Step {
8	  op: string;
9	  items?: Item[];
10	}
11	
12	interface Scenario {
13	  steps: Step[];
14	}
15	
16	const basePremium = (item: Item): number => {
17	  if (item.type === "sword") return 100;
18	  if (item.type === "amulet") return 60;
19	  return 0;
20	};
21	
22	export const runScenario = (scenario: Scenario): unknown => {
23	  const results = scenario.steps.map((step) => {
24	    const items = step.items ?? [];
25	    const total = items.reduce((sum, item) => sum + basePremium(item), 0);
26	    return { premium: total + PROCESSING_FEE };
27	  });
28	  return { results };
29	};
