1	import { describe, it, expect } from "vitest";
2	import { runScenario } from "./claim-office.js";
3	
4	describe("MHPCO Claim Office", () => {
5	  // Quote: empty and single-item basics
6	  it("quote with empty item list returns premium 5 (processing fee only)", () => {
7	    const result = runScenario({
8	      customer: { yearsWithMHPCO: 0 },
9	      steps: [{ op: "quote", items: [] }],
10	    });
11	    expect(result).toEqual({ results: [{ premium: 5 }] });
12	  });
13	  it("quote with a single plain sword returns premium 105", () => {
14	    const result = runScenario({
15	      customer: { yearsWithMHPCO: 0 },
16	      steps: [
17	        {
18	          op: "quote",
19	          items: [{ type: "sword", material: "steel", enchantment: 1, cursed: false }],
20	        },
21	      ],
22	    });
23	    expect(result).toEqual({ results: [{ premium: 105 }] });
24	  });
25	  it("quote with a single plain amulet returns premium 65", () => {
26	    const result = runScenario({
27	      customer: { yearsWithMHPCO: 0 },
28	      steps: [
29	        {
30	          op: "quote",
31	          items: [{ type: "amulet", material: "silver", enchantment: 1, cursed: false }],
32	        },
33	      ],
34	    });
35	    expect(result).toEqual({ results: [{ premium: 65 }] });
36	  });
37	  it.todo("quote with a single plain staff returns premium 85");
38	  it.todo("quote with a single plain potion returns premium 45");
39	
40	  // Quote: multiple items
41	  it.todo("quote with sword + amulet sums base premiums plus fee → 165");
42	
43	  // Components and block-of-3
44	  it.todo("quote with a single rune returns 25 + 5 = 30");
45	  it.todo("quote with 2 runes returns 50 + 5 = 55");
46	  it.todo("quote with 3 runes (block) returns 60 + 5 = 65");
47	  it.todo("quote with 4 runes returns 100 + 5 = 105");
48	  it.todo("quote with 7 runes returns 175 + 5 = 180");
49	  it.todo("quote with 2 runes + 1 moonstone returns 75 + 5 = 80");
50	  it.todo("quote with 3 runes + 3 moonstones returns 120 + 5 = 125");
51	
52	  // Item-specific modifiers
53	  it.todo("cursed sword (steel, enchantment 3, newcomer) → premium 165");
54	  it.todo("sword with enchantment 5 (newcomer) → 100 + 30 = 130 + 5 fee = 135");
55	  it.todo("sword with enchantment 4 (newcomer) → no high-ench surcharge → 105");
56	
57	  // Policy-wide modifiers
58	  it.todo("loyalty discount: 2-year customer with plain sword → 100 − 20 + 5 = 85");
59	  it.todo("first-insurance surcharge: each item in quote adds 10% of its base");
60	  it.todo("follow-up contract: 15% discount applies on second quote");
61	
62	  // Integration
63	  it.todo("newcomer cursed sword integration example → 165");
64	  it.todo("long-standing customer's second contract cursed enchanted sword → 160");
65	
66	  // Rounding
67	  it.todo("premium that yields 197.5 rounds up to 198");
68	
69	  // Errors
70	  it.todo("quote with unknown item type exits non-zero with stderr message");
71	
72	  // Claim: basic
73	  it.todo("claim on plain sword, damage 500 → payout 400, remainingCap 1600");
74	  it.todo("claim on rune, damage 200 → payout 100");
75	
76	  // Claim: special clauses
77	  it.todo("dragon-material sword enchantment 5, damage 800 → payout 700");
78	  it.todo("steel sword enchantment 9, damage 1000 → payout 400");
79	  it.todo("dragon-material sword enchantment 9, damage 1000 → payout 400");
80	  it.todo("dragon-material sword enchantment 8, damage 1000 → payout 400");
81	
82	  // Multiple damages and deductible
83	  it.todo("dragon attack damaging sword 500 and amulet 300 → payout 600");
84	
85	  // Multiple items of same type
86	  it.todo("policy with two swords, both damaged → each has own deductible");
87	  it.todo("damages with more entries of a type than insured → CLI exits non-zero");
88	
89	  // Cap exhaustion
90	  it.todo("sword cap 2000; two claims of 1500 → 1400 then 600");
91	
92	  // Claim errors
